print "Content-type: text/html\r\n";
print "\n";
print "<title>Text Only For You</title>";
print '<body bgcolor="lightblue" text="black">';

use CGI qw( ); # This is not a line for CGI, but is necessary to include CGI
print "Enter Text:<br>";
my $form = CGI->new();
my $comment=$form->param('comment');
print "<div> $comment </div>\n";

use Data::Dumper; # This is not a line for CGI, but is necessary to include CGI 
print Dumper( $form ); # print_form uses Dumper. 

print "</body>";
print "</html>";

end_of_text

